  Future<String> _uploadToS3(Uint8List bytes, String fileName) async {
    final url = Uri.parse('https://$bucketName.$s3Endpoint/$fileName');
    final now = DateTime.now();
    final date = now.toUtc().toIso8601String().split('T')[0];
    final dateTime = now.toUtc().toIso8601String().replaceAll(RegExp(r'[-:T.]'), '');

    final canonicalRequest = 'PUT\n/$fileName\n\nhost:$bucketName.$s3Endpoint\n\nhost\nUNSIGNED-PAYLOAD';
